function isPrime(nums) {

var isPrime = true;

for (var i = 2; i <= nums.length; i++) {

if (nums[i] % i === 0) {

isPrime = false;

break;

}

}

return isPrime;

}

def factorial(n: int) -> int:

if n <= 0:

return 1

else:

return n * factorial(n - 1)

